248→/// [`RevsetExpression`] that may contain unresolved commit refs.
249→pub type UserRevsetExpression = RevsetExpression<UserExpressionState>;
250→/// [`RevsetExpression`] that never contains unresolved commit refs.
251→pub type ResolvedRevsetExpression = RevsetExpression<ResolvedExpressionState>;
