412→/// Defines the interface for commit backends.
413→#[async_trait]
414→pub trait Backend: Any + Send + Sync + Debug {
415→    /// A unique name that identifies this backend. Written to
416→    /// `.jj/repo/store/type` when the repo is created.
417→    fn name(&self) -> &str;
418→
419→    /// The length of commit IDs in bytes.
420→    fn commit_id_length(&self) -> usize;
421→
422→    /// The length of change IDs in bytes.
423→    fn change_id_length(&self) -> usize;
424→
425→    fn root_commit_id(&self) -> &CommitId;
426→
427→    fn root_change_id(&self) -> &ChangeId;
428→
429→    fn empty_tree_id(&self) -> &TreeId;
430→
431→    /// An estimate of how many concurrent requests this backend handles well. A
432→    /// local backend like the Git backend (at until it supports partial clones)
433→    /// may want to set this to 1. A cloud-backed backend may want to set it to
434→    /// 100 or so.
435→    ///
436→    /// It is not guaranteed that at most this number of concurrent requests are
437→    /// sent. It is the backend's responsibility to make sure it doesn't put
438→    /// too much load on its storage, e.g. by queueing requests if necessary.
439→    fn concurrency(&self) -> usize;
440→
441→    async fn read_file(
442→        &self,
443→        path: &RepoPath,
444→        id: &FileId,
445→    ) -> BackendResult<Pin<Box<dyn AsyncRead + Send>>>;
446→
447→    async fn write_file(
448→        &self,
449→        path: &RepoPath,
450→        contents: &mut (dyn AsyncRead + Send + Unpin),
451→    ) -> BackendResult<FileId>;
452→
453→    async fn read_symlink(&self, path: &RepoPath, id: &SymlinkId) -> BackendResult<String>;
454→
455→    async fn write_symlink(&self, path: &RepoPath, target: &str) -> BackendResult<SymlinkId>;
456→
457→    /// Read the specified `CopyHistory` object.
458→    ///
459→    /// Backends that don't support copy tracking may return
460→    /// `BackendError::Unsupported`.
461→    async fn read_copy(&self, id: &CopyId) -> BackendResult<CopyHistory>;
462→
463→    /// Write the `CopyHistory` object and return its ID.
464→    ///
465→    /// Backends that don't support copy tracking may return
466→    /// `BackendError::Unsupported`.
467→    async fn write_copy(&self, copy: &CopyHistory) -> BackendResult<CopyId>;
468→
469→    /// Find all copy histories that are related to the specified one. This is
470→    /// defined as those that are ancestors of the given specified one, plus
471→    /// their descendants. Children must be returned before parents.
472→    ///
473→    /// It is valid (but wasteful) to include other copy histories, such as
474→    /// siblings, or even completely unrelated copy histories.
475→    ///
476→    /// Backends that don't support copy tracking may return
477→    /// `BackendError::Unsupported`.
478→    async fn get_related_copies(&self, copy_id: &CopyId) -> BackendResult<Vec<CopyHistory>>;
479→
480→    async fn read_tree(&self, path: &RepoPath, id: &TreeId) -> BackendResult<Tree>;
481→
482→    async fn write_tree(&self, path: &RepoPath, contents: &Tree) -> BackendResult<TreeId>;
483→
484→    async fn read_commit(&self, id: &CommitId) -> BackendResult<Commit>;
485→
486→    /// Writes a commit and returns its ID and the commit itself. The commit
487→    /// should contain the data that was actually written, which may differ
488→    /// from the data passed in. For example, the backend may change the
489→    /// committer name to an authenticated user's name, or the backend's
490→    /// timestamps may have less precision than the millisecond precision in
491→    /// `Commit`.
492→    ///
493→    /// The `sign_with` parameter could contain a function to cryptographically
494→    /// sign some binary representation of the commit.
495→    /// If the backend supports it, it could call it and store the result in
496→    /// an implementation specific fashion, and both `read_commit` and the
497→    /// return of `write_commit` should read it back as the `secure_sig`
498→    /// field.
499→    async fn write_commit(
500→        &self,
501→        contents: Commit,
502→        sign_with: Option<&mut SigningFn>,
503→    ) -> BackendResult<(CommitId, Commit)>;
504→
505→    /// Get copy records for the dag range `root..head`. If `paths` is None
506→    /// include all paths, otherwise restrict to only `paths`.
507→    ///
508→    /// The exact order these are returned is unspecified, but it is guaranteed
509→    /// to be reverse-topological. That is, for any two copy records with
510→    /// different commit ids A and B, if A is an ancestor of B, A is streamed
511→    /// after B.
512→    ///
513→    /// Streaming by design to better support large backends which may have very
514→    /// large single-file histories. This also allows more iterative algorithms
515→    /// like blame/annotate to short-circuit after a point without wasting
516→    /// unnecessary resources.
517→    fn get_copy_records(
518→        &self,
519→        paths: Option<&[RepoPathBuf]>,
520→        root: &CommitId,
521→        head: &CommitId,
522→    ) -> BackendResult<BoxStream<'_, BackendResult<CopyRecord>>>;
523→
524→    /// Perform garbage collection.
525→    ///
526→    /// All commits found in the `index` won't be removed. In addition to that,
527→    /// objects created after `keep_newer` will be preserved. This mitigates a
528→    /// risk of deleting new commits created concurrently by another process.
529→    fn gc(&self, index: &dyn Index, keep_newer: SystemTime) -> BackendResult<()>;
530→}
531→
532→impl dyn Backend {
533→    /// Returns reference of the implementation type.
534→    pub fn downcast_ref<T: Backend>(&self) -> Option<&T> {
535→        (self as &dyn Any).downcast_ref()
536→    }
537→}
